class Person:
    def __init__(self, förnamn, efternamn, födelseår):
      self.förnamn = förnamn
      self.efternamn = efternamn
      self.födelseår = födelseår

    def __str__(self):
      return self.förnamn + ": " + str(self.födelseår)

    def skriv_intro(self):
      print("Hej jag heter " + self.förnamn + " " + self.efternamn + " och jag är född" + str(self.födelseår))

kim = Person("Kim","Efternamnsson", 1995)
print(kim)
kim.skriv_intro()
